// src/pages/Home.js
import React from 'react';
import { Link } from 'react-router-dom';
import '../styles/Home.css';

const Home = () => {
  return (
    <div className="home-container">
      <section className="hero-section">
        <h1>Welcome to CareAfrica</h1>
        <p>Join us in protecting Africa's wildlife and promoting conservation efforts</p>
        <div className="cta-buttons">
          <Link to="/education" className="btn primary">Learn More</Link>
          <Link to="/donations" className="btn secondary">Donate Now</Link>
        </div>
      </section>

      <section className="features-section">
        <h2>Our Mission</h2>
        <div className="features-grid">
          <div className="feature-card">
            <h3>Education</h3>
            <p>Learn about endangered species and conservation efforts</p>
          </div>
          <div className="feature-card">
            <h3>Community</h3>
            <p>Join our forum and connect with conservation enthusiasts</p>
          </div>
          <div className="feature-card">
            <h3>Events</h3>
            <p>Participate in conservation events and workshops</p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
